import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const STEPS = [
  'Care Type',
  'Patient Details',
  'Requirements',
  'Schedule',
  'Location',
  'Select Caregiver',
  'Review'
];

const initialForm = {
  careType: '',
  patient: { name: '', age: '', gender: '', medicalConditions: '' },
  careRequirements: [],
  schedule: { startDate: '', endDate: '', timeSlot: '', duration: '' },
  location: { address: '', city: '', pincode: '' },
  additionalNotes: ''
};

export default function BookingForm() {
  const [step, setStep] = useState(0);
  const [form, setForm] = useState(initialForm);
  const [caregivers, setCaregivers] = useState([]);
  const [caregiverId, setCaregiverId] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('http://localhost:5000/api/caregivers')
      .then(res => setCaregivers(res.data))
      .catch(err => console.log(err));
  }, []);

  const setPatient = (f, v) => setForm(prev => ({ ...prev, patient: { ...prev.patient, [f]: v } }));
  const setSchedule = (f, v) => setForm(prev => ({ ...prev, schedule: { ...prev.schedule, [f]: v } }));
  const setLocation = (f, v) => setForm(prev => ({ ...prev, location: { ...prev.location, [f]: v } }));

  const canNext = () => {
    if (step === 0) return form.careType;
    if (step === 1) return form.patient.name && form.patient.age;
    if (step === 2) return form.careRequirements.length > 0;
    if (step === 3) return form.schedule.startDate;
    if (step === 4) return form.location.address;
    if (step === 5) return caregiverId;
    return true;
  };

  const handleSubmit = async () => {
    try {
      await axios.post('http://localhost:5000/api/bookings', {
        ...form,
        caregiverId
      });
      alert("Booking Successful!");
      navigate('/dashboard');
    } catch (err) {
      console.log(err);
      alert("Booking failed");
    }
  };

  return (
    <div style={{ padding: 30 }}>

      <h2>Step {step + 1}: {STEPS[step]}</h2>

      {/* STEP 0 */}
      {step === 0 && (
        <select onChange={(e) => setForm({ ...form, careType: e.target.value })}>
          <option value="">Select Care Type</option>
          <option value="elderly">Elderly</option>
          <option value="maternity">Pregnant Woman</option>
          <option value="childcare">Child</option>
        </select>
      )}

      {/* STEP 1 */}
      {step === 1 && (
        <>
          <input placeholder="Name" onChange={e => setPatient('name', e.target.value)} />
          <input placeholder="Age" onChange={e => setPatient('age', e.target.value)} />
        </>
      )}

      {/* STEP 2 */}
      {step === 2 && (
        <button onClick={() =>
          setForm(prev => ({
            ...prev,
            careRequirements: ['daily_assistance']
          }))
        }>
          Add Requirement
        </button>
      )}

      {/* STEP 3 */}
      {step === 3 && (
        <input type="date" onChange={e => setSchedule('startDate', e.target.value)} />
      )}

      {/* STEP 4 */}
      {step === 4 && (
        <input placeholder="Address" onChange={e => setLocation('address', e.target.value)} />
      )}

      {/* STEP 5 (IMPORTANT) */}
      {step === 5 && (
        <select value={caregiverId} onChange={(e) => setCaregiverId(e.target.value)}>
          <option value="">Select Caregiver</option>
          {caregivers.map(cg => (
            <option key={cg._id} value={cg._id}>
              {cg.user.name} - {cg.specializations.join(', ')}
            </option>
          ))}
        </select>
      )}

      {/* STEP 6 */}
      {step === 6 && (
        <div>
          <h3>Review</h3>
          <p>Care Type: {form.careType}</p>
          <p>Patient: {form.patient.name}</p>
          <p>Caregiver Selected: {caregiverId}</p>
        </div>
      )}

      <br />

      {/* NAVIGATION */}
      {step > 0 && <button onClick={() => setStep(step - 1)}>Back</button>}

      {step < STEPS.length - 1 ? (
        <button onClick={() => setStep(step + 1)} disabled={!canNext()}>
          Next
        </button>
      ) : (
        <button onClick={handleSubmit}>
          Submit
        </button>
      )}

    </div>
  );
}
